import React from 'react';

/**
 * HourStack 3D SVG logo.
 * A stylised clock face sitting on stacked depth layers — giving an isometric 3D feel.
 * Colour palette inherits from the navbar (white on orange) via the `color` prop.
 */
export default function HourStackLogo({ size = 36, color = '#ffffff' }) {
  const id = 'hs'; // gradient id prefix
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 48 48"
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      style={{ display: 'block', filter: 'drop-shadow(0 2px 4px rgba(0,0,0,0.35))' }}
      aria-label="HourStack logo"
    >
      <defs>
        {/* Front face gradient — light top-left to darker bottom-right */}
        <radialGradient id={`${id}-face`} cx="38%" cy="32%" r="62%">
          <stop offset="0%" stopColor="#ffffff" stopOpacity="1" />
          <stop offset="100%" stopColor="#d4e8ff" stopOpacity="1" />
        </radialGradient>
        {/* Rim / bezel gradient */}
        <linearGradient id={`${id}-rim`} x1="0%" y1="0%" x2="100%" y2="100%">
          <stop offset="0%" stopColor="#5b9bd5" />
          <stop offset="50%" stopColor="#2a6db5" />
          <stop offset="100%" stopColor="#1a4a80" />
        </linearGradient>
        {/* Bottom stack layer */}
        <linearGradient id={`${id}-stack1`} x1="0%" y1="0%" x2="0%" y2="100%">
          <stop offset="0%" stopColor="#1a4a80" />
          <stop offset="100%" stopColor="#0d2e52" />
        </linearGradient>
        {/* Middle stack layer */}
        <linearGradient id={`${id}-stack2`} x1="0%" y1="0%" x2="0%" y2="100%">
          <stop offset="0%" stopColor="#2a6db5" />
          <stop offset="100%" stopColor="#1a4a80" />
        </linearGradient>
        {/* Highlight arc on bezel */}
        <linearGradient id={`${id}-shine`} x1="20%" y1="0%" x2="80%" y2="100%">
          <stop offset="0%" stopColor="#ffffff" stopOpacity="0.6" />
          <stop offset="100%" stopColor="#ffffff" stopOpacity="0" />
        </linearGradient>
      </defs>

      {/* ── Stack layers (3D depth) ── */}
      {/* Bottom layer (shadow) */}
      <ellipse cx="24" cy="46" rx="14" ry="3" fill="rgba(0,0,0,0.2)" />
      {/* Layer 3 — deepest */}
      <rect x="10" y="36" width="28" height="5" rx="2" fill={`url(#${id}-stack1)`} />
      {/* Layer 2 — middle */}
      <rect x="10" y="31" width="28" height="5" rx="2" fill={`url(#${id}-stack2)`} />

      {/* ── Clock bezel (thick ring) ── */}
      <circle cx="24" cy="22" r="14" fill={`url(#${id}-rim)`} />
      {/* Bezel shine arc */}
      <circle cx="24" cy="22" r="14" fill={`url(#${id}-shine)`} />

      {/* ── Clock face ── */}
      <circle cx="24" cy="22" r="11" fill={`url(#${id}-face)`} />

      {/* ── Hour markers (12 short ticks) ── */}
      {[0, 30, 60, 90, 120, 150, 180, 210, 240, 270, 300, 330].map((deg, i) => {
        const rad = (deg - 90) * (Math.PI / 180);
        const x1 = 24 + 9.2 * Math.cos(rad);
        const y1 = 22 + 9.2 * Math.sin(rad);
        const x2 = 24 + (i % 3 === 0 ? 7.6 : 8.2) * Math.cos(rad);
        const y2 = 22 + (i % 3 === 0 ? 7.6 : 8.2) * Math.sin(rad);
        return (
          <line
            key={deg}
            x1={x1} y1={y1} x2={x2} y2={y2}
            stroke="#2a6db5"
            strokeWidth={i % 3 === 0 ? 1.4 : 0.8}
            strokeLinecap="round"
          />
        );
      })}

      {/* ── Clock hands ── */}
      {/* Hour hand — pointing to ~10 */}
      <line
        x1="24" y1="22"
        x2={24 + 5.5 * Math.cos((300 - 90) * Math.PI / 180)}
        y2={22 + 5.5 * Math.sin((300 - 90) * Math.PI / 180)}
        stroke="#1a4a80" strokeWidth="2" strokeLinecap="round"
      />
      {/* Minute hand — pointing to ~2 */}
      <line
        x1="24" y1="22"
        x2={24 + 7.5 * Math.cos((60 - 90) * Math.PI / 180)}
        y2={22 + 7.5 * Math.sin((60 - 90) * Math.PI / 180)}
        stroke="#1a4a80" strokeWidth="1.5" strokeLinecap="round"
      />
      {/* Second hand — red accent */}
      <line
        x1="24" y1="22"
        x2={24 + 8.5 * Math.cos((180 - 90) * Math.PI / 180)}
        y2={22 + 8.5 * Math.sin((180 - 90) * Math.PI / 180)}
        stroke="#e74c3c" strokeWidth="1" strokeLinecap="round"
      />
      {/* Centre dot */}
      <circle cx="24" cy="22" r="1.2" fill="#1a4a80" />
      <circle cx="24" cy="22" r="0.6" fill="#e74c3c" />
    </svg>
  );
}
